INSERT INTO business(bus_name, counc_id_pk, bus_phone, bus_email, bus_url, bus_bio) VALUES ("Monica's Mugs", '10', '07457 123456', 'contact@monsmugs.co.uk', 'monsmugs.co.uk', "Monica's Mugs is a small business based in Hatfield. We create handcrafted stoneware inspired by the countryside around Hatfield.");
INSERT INTO business(bus_name, counc_id_pk, bus_phone, bus_email, bus_url, bus_bio) VALUES ("British Schools Museum", '5', '(01462) 420144', 'enquiries@britishschoolsmuseum.org.uk', 'https://britishschoolsmuseum.org.uk/', "Discover the fascinating story of education through the ages at the British Schools Museum in Hitchin. Housed in a remarkable Grade II* listed building dating back to 1837, the museum is home to the world's last surviving galleried monitorial schoolroom — a truly unique piece of history. Walk in the footsteps of Victorian pupils, explore hands-on exhibits, and bring the past to life for the whole family. Whether you're a history enthusiast, a curious child, or a school group on a curriculum trip, the British Schools Museum offers an unforgettable journey into Britain's educational heritage.");